import{_ as a,c as i,ag as t,o}from"./chunks/framework.-a8jReyC.js";const n="/assets/nextjs-ai.CYG49x3L.webp",r="/assets/architecture.vyn5JI8_.svg",g=JSON.parse('{"title":"What is SQLRooms?","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),s={name:"overview.md"};function l(c,e,d,u,h,p){return o(),i("div",null,e[0]||(e[0]=[t('<h1 id="what-is-sqlrooms" tabindex="-1">What is SQLRooms? <a class="header-anchor" href="#what-is-sqlrooms" aria-label="Permalink to &quot;What is SQLRooms?&quot;">​</a></h1><p>SQLRooms provides a foundation and set of building blocks for creating data analytics applications that run entirely in the browser. It combines essential components like a SQL query engine (DuckDB), data visualization tools, state management, and UI components into a cohesive toolkit, making it significantly easier to create powerful analytics tools without a backend.</p><p><img src="'+n+'" alt="NextJS AI app"></p><h2 id="who-is-it-for" tabindex="-1">Who is it for? <a class="header-anchor" href="#who-is-it-for" aria-label="Permalink to &quot;Who is it for?&quot;">​</a></h2><p>SQLRooms is designed for developers building:</p><ul><li>Interactive data analysis tools</li><li>Custom BI solutions</li><li>Data visualization applications</li><li>Internal analytics dashboards</li></ul><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Modern data analytics applications face several challenges that SQLRooms addresses:</p><h3 id="performance-and-scale" tabindex="-1">Performance and Scale <a class="header-anchor" href="#performance-and-scale" aria-label="Permalink to &quot;Performance and Scale&quot;">​</a></h3><p>DuckDB is purpose-built for analytics, providing fast query performance on large datasets through its columnar engine and optimized query processing. Running in the browser through WebAssembly, each user gets their own instance, enabling automatic scaling without infrastructure costs. Applications can even work offline, as there&#39;s no dependency on backend services.</p><h3 id="ai-powered-analytics" tabindex="-1">AI-Powered Analytics <a class="header-anchor" href="#ai-powered-analytics" aria-label="Permalink to &quot;AI-Powered Analytics&quot;">​</a></h3><p>The browser-based DuckDB engine enables powerful AI-driven analytics workflows:</p><ul><li>Interactive AI agents that can write and execute SQL queries</li><li>Automated data analysis and insights generation</li></ul><p>Check out our <a href="/examples/#ai-powered-analytics-next-js">Next.js AI example</a> that demonstrates how to build an AI agent that can analyze your data using natural language, execute SQL queries, and provide insights – all running directly in the browser.</p><h3 id="privacy-and-security" tabindex="-1">Privacy and Security <a class="header-anchor" href="#privacy-and-security" aria-label="Permalink to &quot;Privacy and Security&quot;">​</a></h3><p>SQLRooms enables applications where sensitive data can remain completely client-side, as all data processing and analysis can be performed directly in the browser using DuckDB. This architecture allows for implementations where data never needs to leave the client, simplifying compliance and security requirements when needed.</p><h3 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to &quot;Developer Experience&quot;">​</a></h3><p>Building analytics applications typically requires integrating multiple complex components. SQLRooms provides a complete foundation with state management, UI components, and extensible architecture out of the box.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>SQLRooms is built around several core components that work together seamlessly:</p><p><img src="'+r+'" alt="SQLRooms Architecture"></p><h3 id="core-components" tabindex="-1">Core Components <a class="header-anchor" href="#core-components" aria-label="Permalink to &quot;Core Components&quot;">​</a></h3><h4 id="projectstore" tabindex="-1">ProjectStore <a class="header-anchor" href="#projectstore" aria-label="Permalink to &quot;ProjectStore&quot;">​</a></h4><p>The central state management system built on Zustand handles:</p><ul><li>Project configuration and persistence</li><li>Data source management</li><li>DuckDB integration</li><li>Type-safe state management</li></ul><p>The ProjectStore can be extended with custom configuration and functionality specific to your needs.</p><h4 id="project-builder" tabindex="-1">Project Builder <a class="header-anchor" href="#project-builder" aria-label="Permalink to &quot;Project Builder&quot;">​</a></h4><p>Provides the application shell with:</p><ul><li>Configurable and pluggable views</li><li>Flexible panel layouts</li><li>Sidebar and main view management</li></ul><h4 id="built-in-views" tabindex="-1">Built-in Views <a class="header-anchor" href="#built-in-views" aria-label="Permalink to &quot;Built-in Views&quot;">​</a></h4><p>Ready-to-use components accelerate development:</p><ul><li>DataTable View for displaying and interacting with query results</li><li>S3 Browser for managing data sources and importing data</li><li>SQL Query Editor with syntax highlighting</li></ul><h3 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h3><p>The framework is designed to be highly extensible through:</p><ol><li><p><strong>Extended ProjectStore</strong></p><ul><li>Custom project configuration using Zod schemas</li><li>Additional state management</li><li>Integration with other services</li></ul></li><li><p><strong>Custom Views and Panels</strong></p><ul><li>Create specialized views for specific use cases</li><li>Configure panel layouts and behavior</li><li>Integrate with existing panel management</li></ul></li></ol><h3 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h3><ol><li>Data sources (CSV, Parquet) are loaded through the S3 browser or custom import methods</li><li>DuckDB processes queries locally in the browser</li><li>Results are displayed in the DataTable view or custom visualizations</li><li>Project state can be saved and loaded for persistence</li></ol><h2 id="framework-features" tabindex="-1">Framework Features <a class="header-anchor" href="#framework-features" aria-label="Permalink to &quot;Framework Features&quot;">​</a></h2><h3 id="ui-components" tabindex="-1">UI Components <a class="header-anchor" href="#ui-components" aria-label="Permalink to &quot;UI Components&quot;">​</a></h3><p>A professional set of components built with Tailwind CSS provides a consistent, responsive interface out of the box. The panel system allows flexible layouts while maintaining a cohesive look and feel.</p><h3 id="duckdb-integration" tabindex="-1">DuckDB Integration <a class="header-anchor" href="#duckdb-integration" aria-label="Permalink to &quot;DuckDB Integration&quot;">​</a></h3><p>SQLRooms provides deep integration with DuckDB through built-in utilities that:</p><ul><li>Manage the DuckDB-WASM instance lifecycle</li><li>Handle data source connections and imports</li><li>Execute SQL queries and manage results</li><li>Provide type-safe query results</li></ul>',43)]))}const b=a(s,[["render",l]]);export{g as __pageData,b as default};
